bool unique_chars_in_string(char* s) {
    // Using two 32-bit integers to track character presence for full ASCII range
    unsigned int checker1 = 0; // For characters 0-31
    unsigned int checker2 = 0; // For characters 32-63
    unsigned int checker3 = 0; // For characters 64-95
    unsigned int checker4 = 0; // For characters 96-127

    for (int i = 0; s[i] != '\0'; i++) {
        unsigned char ch = (unsigned char)s[i];
        int bit_pos = ch % 32;
        unsigned int* checker;

        // Select appropriate checker based on character value
        if (ch < 32) {
            checker = &checker1;
        } else if (ch < 64) {
            checker = &checker2;
        } else if (ch < 96) {
            checker = &checker3;
        } else {
            checker = &checker4;
        }

        // Check if this bit is already set
        if ((*checker & (1U << bit_pos)) != 0) {
            return false;
        }

        // Set the bit for this character
