private int checkBalanceProperties(Node node, int expectedBlackHeight) {
    // Base case: reached a leaf (null node)
    if (node == null) return 1; // Null nodes are black

    // Red node property check: red nodes cannot have red children
    if (isRed(node)) {
        if (isRed(node.left) || isRed(node.right))
            return -1; // Violation: red node with red child
    }

    // Check left subtree
    int leftHeight = checkBalanceProperties(node.left, expectedBlackHeight);
    if (leftHeight < 0) return -1; // Propagate violation

    // Check right subtree
    int rightHeight = checkBalanceProperties(node.right, expectedBlackHeight);
    if (rightHeight < 0) return -1; // Propagate violation

    // Check if black heights are equal
    if (leftHeight != rightHeight) return -1;

    // Calculate current path's black height
    int currentBlackHeight = leftHeight + (isRed(node) ? 0 : 1);

    // If expectedBlackHeight is not set, set it from the first complete path
    if (expectedBlackHeight < 0) {
        return currentBlackHeight;
    }

    // Otherwise verify it matches expected black height
    return (currentBlackHeight == expectedBlackHeight) ? currentBlackHeight : -1;
}

