impl<T: Ord> FibonacciHeap<T> {
    pub fn new() -> Self {
        FibonacciHeap {
            min: None,
            size: 0,
        }
    }

    pub fn insert(&mut self, key: T) {
        let mut node = Box::new(Node {
            key,
            degree: 0,
            marked: false,
            parent: None,
            child: None,
            left: std::ptr::null_mut(),
            right: std::ptr::null_mut(),
        });

