        node.left = node_ptr;
        node.right = node_ptr;

        if let Some(min) = &mut self.min {
            // Add to circular list
            let min_ptr: *mut Node<T> = &mut **min;
            node.right = min_ptr;
            node.left = min.left;
            unsafe {
                (*min.left).right = node_ptr;
                min.left = node_ptr;
            }

            // Update min if needed
            if node.key < min.key {
                self.min = Some(node);
            }
        } else {
            self.min = Some(node);
        }

        self.size += 1;
    }

    pub fn extract_min(&mut self) -> Option<T> {
        self.min.take().map(|min_node| {
            self.size -= 1;

            // If there are children, add them to the root list
            if let Some(mut child) = min_node.child {
                let child_ptr: *mut Node<T> = &mut *child;
                let mut current = child_ptr;

                // Update parent pointers
                unsafe {
                    loop {
                        (*current).parent = None;
                        current = (*current).right;
                        if current == child_ptr {
                            break;
                        }
                    }
                }

                // Merge child list with root list if root list is not empty
                if self.min.is_some() {
                    let min_ptr = &mut **self.min.as_mut().unwrap();
                    unsafe {
                        let min_left = min_ptr.left;
                        let child_left = child.left;

                        min_ptr.left = child_left;
                        (*child_left).right = min_ptr as *mut Node<T>;
                        child.left = min_left;
                        (*min_left).right = &mut *child;
                    }
                } else {
                    // Child list becomes the root list
                    self.min = Some(child);
                }
            }

            // If this was the last node, we're done
            if self.size == 0 {
                return min_node.key;
            }

            // Consolidate trees
            self.consolidate();

            min_node.key
        })
