    private static class Node implements Comparable<Node> {
        char ch;
        int freq;
        Node left, right;

        Node(char ch, int freq) {
            this.ch = ch;
            this.freq = freq;
            left = right = null;
        }

        Node(char ch, int freq, Node left, Node right) {
            this.ch = ch;
            this.freq = freq;
            this.left = left;
            this.right = right;
        }

        @Override
        public int compareTo(Node other) {
            return this.freq - other.freq;
        }
    }

    public static String compressData(String input) {
        if (input == null || input.isEmpty()) {
            return "";
        }

        // Count frequency of each character - O(n) space as we have at most unique characters
        int[] freqArray = new int[256]; // Assuming ASCII characters only
        for (char c : input.toCharArray()) {
            freqArray[c]++;
        }

        // Build Huffman Tree using array-based approach
        PriorityQueue<Node> minHeap = new PriorityQueue<>();
        for (int i = 0; i < 256; i++) {
            if (freqArray[i] > 0) {
                minHeap.offer(new Node((char)i, freqArray[i]));
            }
        }

        // Create Huffman tree by combining nodes
        while (minHeap.size() > 1) {
            Node left = minHeap.poll();
            Node right = minHeap.poll();
            minHeap.offer(new Node('\0', left.freq + right.freq, left, right));
        }

        Node root = minHeap.poll();

        // Generate codes for each character - limited to 256 characters max
        String[] codes = new String[256];
        generateCodes(root, "", codes);

        // Build compressed string
        StringBuilder compressed = new StringBuilder();
        for (char c : input.toCharArray()) {
            compressed.append(codes[c]);
        }

        // Store tree structure and compressed data
        StringBuilder result = new StringBuilder();

        // Store character codes for decompression - only for characters that appear
        for (int i = 0; i < 256; i++) {
            if (codes[i] != null) {
                result.append((char)i)
                      .append(':')
                      .append(codes[i])
                      .append(';');
            }
        }

        // Separator between codes and compressed data
        result.append('|').append(compressed);

        return result.toString();
    }

    private static void generateCodes(Node root, String code, String[] codes) {
        if (root == null) {
            return;
        }

        // Found a leaf node with a character
        if (root.left == null && root.right == null) {
            codes[root.ch] = code.length() > 0 ? code : "0";
        }

        generateCodes(root.left, code + "0", codes);
        generateCodes(root.right, code + "1", codes);
    }
}

