        if self.rank[root_x] < self.rank[root_y] {
            self.parent[root_x] = root_y;
        } else if self.rank[root_x] > self.rank[root_y] {
            self.parent[root_y] = root_x;
        } else {
            self.parent[root_y] = root_x;
            self.rank[root_x] += 1;
        }
    }
}

fn union_find(n: usize, edges: &[(usize, usize)]) -> Vec<Vec<usize>> {
    let mut ds = DisjointSet::new(n);

    // Perform union operations for all edges
    for &(u, v) in edges {
        ds.union(u, v);
    }

    // Group elements by their root
    let mut components = vec![Vec::new(); n];
    let mut active_roots = Vec::with_capacity(n);

    for i in 0..n {
        let root = ds.find(i);
        components[root].push(i);

        if root == i {
            active_roots.push(root);
        }
    }

    // Return only non-empty components
    active_roots.iter().map(|&root| components[root].clone()).collect()
}
