def find_common_hobbies(hobbies1, hobbies2):
    # Sort both lists in place - doesn't require additional space
    hobbies1.sort()
    hobbies2.sort()

    common_hobbies = []
    i, j = 0, 0

    # Use two pointers to find common elements
    while i < len(hobbies1) and j < len(hobbies2):
        if hobbies1[i] == hobbies2[j]:
            # Add to result if it's not already there (handles duplicates)
            if not common_hobbies or common_hobbies[-1] != hobbies1[i]:
                common_hobbies.append(hobbies1[i])
            i += 1
            j += 1
        elif hobbies1[i] < hobbies2[j]:
            i += 1
        else:
            j += 1

    return common_hobbies

def main():
